import re

def calculate_maximum_support_percentage(newick_string):
    """
    Parses a Newick string to find all internal node support values (boot/altr)
    and calculates the percentage that have 100/100 support.
    
    Support values are expected in the format: )BOOT/ALTR:branch_length
    """
    # Pattern to find the support values (e.g., 100/100 or 86.6/93) immediately 
    # preceding a colon and branch length, which denotes an internal node.
    pattern = r'\)(\d+\.?\d*)/(\d+\.?\d*):'
    
    # Find all matches (Bootstrap and aLRT values)
    matches = re.findall(pattern, newick_string)
    
    if not matches:
        print("Error: No support values in the format BOOT/ALTR found in the Newick string.")
        return 0.0

    total_nodes_with_support = len(matches)
    
    # Count how many nodes have exactly 100/100 support
    max_support_count = 0
    for boot_str, altr_str in matches:
        # Convert strings to float/int for comparison
        boot = float(boot_str)
        altr = float(altr_str)
        
        # We consider support of 100.0 or 100 to be max
        if boot == 100 and altr == 100:
            max_support_count += 1
            
    percentage = (max_support_count / total_nodes_with_support) * 100
    
    print(f"--- Support Analysis Results ---")
    print(f"Total internal nodes analyzed: {total_nodes_with_support}")
    print(f"Nodes with 100/100 support: {max_support_count}")
    print(f"Percentage of clades with maximum (100/100) support: {percentage:.2f}%")
    
    return percentage

